import {
  Person,
  PermIdentity,
  LocalShippingOutlined,
  CalendarToday,
  Place,
  MailOutline,
} from "@material-ui/icons";
import { Link, useLocation } from "react-router-dom";
import { useSelector } from 'react-redux';
import "./order.css";
import {format} from 'timeago.js';
import { useState } from "react";
import { DataGrid } from "@material-ui/data-grid";
import { 
  Dialog, 
  DialogTitle, 
  DialogActions, 
  Button 
} from '@material-ui/core';

const Order = () => {
  const location = useLocation();
  const orderId = location.pathname.split("/")[2];
  
  const order = useSelector((state) => 
  state.order.orders.find(order => order._id === orderId)
  );
  
  const [orderState, setOrderState] = useState(order);

  const handleUpdateOrder = () => {

  }

  const columns = [
    { field: "productId", headerName: "Product ID", width: 200},
    { field: "title", headerName: "Product Title", width: 200 },
    { field: "color", headerName: "Color", width: 150 },
    { field: "quantity", headerName: "Quantity", width: 150 },
    { field: "price", headerName: "Price for 100 kg", width: 200 },
    {
        field: "price_for_product",
        headerName: "Price for Product",
        width: 200,
        renderCell: (params) => {
            return (
                <div>
                    {params.row.quantity * params.row.price}
                </div>
            )
        }
    }
  ]

  return (
    <div className="order">
        <h1 className="orderTitle">Order ID {order._id}</h1>
        <div className="personalInfo">
            <div className="left">
                <div className="infoTitle">
                    <Person />
                    <h2>Personal Information</h2>
                </div>
                <div className="infoLine">
                    <p className="infoLineTitle"><PermIdentity className="userShowIcon"/> User ID:</p>
                    <p>{order.userId}</p>
                </div>
                <div className="infoLine">
                    <p className="infoLineTitle"><MailOutline className="userShowIcon"/> User Email:</p>
                    <p>{order.email}</p>
                </div>
                <div className="infoLine">
                    <p className="infoLineTitle"><LocalShippingOutlined className="userShowIcon"/> Order Status:</p>
                    <select 
                        name="status" 
                        defaultValue={order.status} 
                        className={"status_" + orderState.status}
                        onChange={(e) => {setOrderState({
                            ...orderState,
                            status: e.target.value
                        })}}
                    >
                        <option value="approved">approved</option>
                        <option value="shipped">shipped</option>
                        <option value="declined">declined</option>
                        <option value="delivered">delivered</option>
                        <option value="pending">pending</option>
                    </select>
                </div>
                <div className="infoLine">
                    <p className="infoLineTitle"><CalendarToday className="userShowIcon"/> Created At:</p>
                    <p>{format(order.createdAt)}</p>
                </div>
                <div className="infoLine">
                    <p className="infoLineTitle"><CalendarToday className="userShowIcon"/> Updated At:</p>
                    <p>{format(order.updatedAt)}</p>
                </div>
            </div>
            <div className="right">
                <div className="infoTitle">
                    <Place />
                    <h2>Address</h2>
                </div>
                <div className="infoLine">
                    <p className="infoLineTitle">Street:</p>
                    <p>{order.address?.line1}</p>
                </div>    
                <div className="infoLine">
                    <p className="infoLineTitle"></p>
                    <p>{order.address?.line2}</p>
                </div>
                <div className="infoLine">
                    <p className="infoLineTitle">City:</p>
                    <p>{order.address?.city}</p>
                </div>
                <div className="infoLine">
                    <p className="infoLineTitle">State:</p>
                    <p>{order.address?.state}</p>
                </div>
                <div className="infoLine">
                    <p className="infoLineTitle">Post Code:</p>
                    <p>{order.address?.postal_code}</p>
                </div> 
            </div>
        </div>
        <div className="productsInfo">
            <DataGrid 
                rows={order.products}
                disableSelectionOnClick
                columns={columns}
                getRowId={(row) => row._id}
                pageSize={8}
                checkboxSelection
            />
        </div>
    </div>
  );
};

export default Order;
